def solve(weight_kg, height_cm, age_years, gender):
    # Step 1: Calculate the BMR for a male patient using the Mifflin-St Jeor formula
    bmr_male = 10 * weight_kg + 6.25 * height_cm - 5 * age_years + 5
    yield {
        "step_name": "calculate_bmr_for_male",
        "step_description": "Calculate the Basal Metabolic Rate (BMR) for a male patient using the Mifflin-St Jeor formula.",
        "step_result": bmr_male,
        "unit": "kcal/day"
    }

    # Step 2: Calculate the BMR for a female patient using the Mifflin-St Jeor formula
    bmr_female = 10 * weight_kg + 6.25 * height_cm - 5 * age_years - 161
    yield {
        "step_name": "calculate_bmr_for_female",
        "step_description": "Calculate the Basal Metabolic Rate (BMR) for a female patient using the Mifflin-St Jeor formula.",
        "step_result": bmr_female,
        "unit": "kcal/day"
    }

    # Step 3: Select the appropriate BMR value based on the patient's gender
    if gender == "Male":
        bmr_value = bmr_male
    else:
        bmr_value = bmr_female
    yield {
        "step_name": "select_bmr_based_on_gender",
        "step_description": "Select the appropriate BMR value based on the patient's gender.",
        "step_result": bmr_value,
        "unit": "kcal/day"
    }

    return bmr_value
